1813→                        }
1814→                    }
1815→                } else {
1816→                    resultIdMapping = messageStore.moveMessages(messageIds, destFolderId);
1817→
1818→                    unsuppressMessages(account, messages);
1819→
1820→                    if (unreadCountAffected) {
1821→                        // If this move operation changes the unread count, notify the listeners
1822→                        // that the unread count changed in both the source and destination folder.
1823→                        for (MessagingListener l : getListeners()) {
1824→                            l.folderStatusChanged(account, srcFolderId);
1825→                            l.folderStatusChanged(account, destFolderId);
1826→                        }
1827→                    }
1828→                }
1829→
1830→                Map<Long, String> destinationMapping = messageStore.getMessageServerIds(resultIdMapping.values());
1831→
1832→                Map<String, String> uidMap = new HashMap<>();
1833→                for (Entry<Long, Long> entry : resultIdMapping.entrySet()) {
