847→    private void queueMoveOrCopy(Account account, long srcFolderId, long destFolderId, MoveOrCopyFlavor operation,
848→            Map<String, String> uidMap) {
849→        PendingCommand command;
850→        switch (operation) {
851→            case MOVE:
852→                command = PendingMoveOrCopy.create(srcFolderId, destFolderId, false, uidMap);
853→                break;
854→            case COPY:
855→                command = PendingMoveOrCopy.create(srcFolderId, destFolderId, true, uidMap);
856→                break;
857→            case MOVE_AND_MARK_AS_READ:
858→                command = PendingMoveAndMarkAsRead.create(srcFolderId, destFolderId, uidMap);
859→                break;
860→            default:
861→                return;
862→        }
863→        queuePendingCommand(account, command);
864→    }
