866→    void processPendingMoveOrCopy(PendingMoveOrCopy command, Account account) throws MessagingException {
867→        long srcFolder = command.srcFolderId;
868→        long destFolder = command.destFolderId;
869→        MoveOrCopyFlavor operation = command.isCopy ? MoveOrCopyFlavor.COPY : MoveOrCopyFlavor.MOVE;
870→
871→        Map<String, String> newUidMap = command.newUidMap;
872→        List<String> uids = newUidMap != null ? new ArrayList<>(newUidMap.keySet()) : command.uids;
873→
874→        processPendingMoveOrCopy(account, srcFolder, destFolder, uids, operation, newUidMap);
875→    }
