877→    void processPendingMoveAndRead(PendingMoveAndMarkAsRead command, Account account) throws MessagingException {
878→        long srcFolder = command.srcFolderId;
879→        long destFolder = command.destFolderId;
880→        Map<String, String> newUidMap = command.newUidMap;
881→        List<String> uids = new ArrayList<>(newUidMap.keySet());
882→
883→        processPendingMoveOrCopy(account, srcFolder, destFolder, uids,
884→                MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ, newUidMap);
885→    }
